#!/usr/bin/perl
use strict;
use warnings;
use Digest::MD5 qw(md5_hex);
use Storable;

# Session directory
my $sess_dir = "/tmp";

# Function to create a new session
sub create_session {
    my ($data) = @_;
    my $session_id = md5_hex(rand(2**32));
    my $file_path = "$sess_dir/sess_$session_id";
    store($data, $file_path);
    return $session_id;
}

# Function to load a session
sub load_session {
    my ($session_id) = @_;
    my $file_path = "$sess_dir/sess_$session_id";
    if (-f $file_path) {
        return retrieve($file_path);
    } else {
        return undef;
    }
}

# Function to save a session
sub save_session {
    my ($data, $session_id) = @_;
    my $file_path = "$sess_dir/sess_$session_id";
    store($data, $file_path);
}

# Function to delete a session
sub delete_session {
    my ($session_id) = @_;
    my $file_path = "$sess_dir/sess_$session_id";
    unlink($file_path);
}

# Load session from cookie
my $cookie_session_id = $ENV{'HTTP_COOKIE'};
if ($cookie_session_id) {
    my @cookies = split(/;/, $cookie_session_id);
    foreach my $cookie (@cookies) {
        if ($cookie =~ /^session_id=(.*)$/) {
            my $session_id = $1;
            my $data = load_session($session_id);
            # Do something with the session data
            print "Session loaded: ", Dumper($data), "\n";
        }
    }
} else {
    # Create a new session if none exists
    my $new_session_id = create_session({});
    my $data = {};
    save_session($data, $new_session_id);
}